        fun `Given a wildcard import from kotlinx_android_synthetic then report a lint error`() {
            val code =
                """
                import kotlinx.android.synthetic.main.layout_name.*
                """.trimIndent()
            noWildcardImportsRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
                .hasLintViolationWithoutAutoCorrect(1, 1, "Wildcard import")
        }

        @Test
        fun `Given multiple wildcard imports then report lint errors for all of them`() {
            val code =
                """
                import java.util.*
                import kotlinx.android.synthetic.main.layout_name.*
                import foo.bar.*
                """.trimIndent()
