                """.trimIndent()
            noWildcardImportsRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to intellij_idea)
                .hasNoLintViolations()
        }

        @Test
        fun `Given a wildcard import from kotlinx_android_synthetic then do not report a lint error`() {
            val code =
                """
                import kotlinx.android.synthetic.main.layout_name.*
                """.trimIndent()
            noWildcardImportsRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to intellij_idea)
                .hasNoLintViolations()
        }

        @Test
        fun `Given other wildcard imports then report lint errors`() {
